+type ErrorStackSerializationMode = 'off' | 'string' | 'frames';
+
+function shouldUseErrorStackMode(
+  error: Error,
+  superJson: SuperJSON,
+  mode: Exclude<ErrorStackSerializationMode, 'off'>
+): boolean {
+  const options = superJson.errorStackOptions;
+  return !!options && options.mode === mode && superJson.matchesErrorStackClass(error);
+}
+
+function serializeError(
+  error: Error,
+  superJson: SuperJSON,
+  mode: ErrorStackSerializationMode
+): Record<string, any> {
+  const options = superJson.errorStackOptions;
+  const matches = !!options && superJson.matchesErrorStackClass(error);
+  const message =
+    options?.sanitizeMessage && matches
+      ? sanitizeMessage(error.message)
+      : error.message;
+  const baseError: Record<string, any> = { name: error.name, message };
+
+  if (!options) {
+    if ('cause' in error) baseError.cause = (error as any).cause;
+  } else if (options.includeCauses !== 'none') {
+    const depth = superJson.getErrorCauseDepth(error);
+    const canInclude =
+      options.includeCauses === 'direct' ? depth === 0 : depth < options.maxCauseDepth;
+    const cause = (error as any).cause;
+    if (canInclude && isError(cause)) {
+      superJson.setErrorCauseDepth(cause, depth + 1);
+      baseError.cause = cause;
+    }
+  }
+
+  if ('errors' in error) baseError.errors = (error as any).errors;
+
+  superJson.allowedErrorProps.forEach(prop => {
+    if (options && (prop === 'stack' || prop === 'stackFrames')) return;
+    baseError[prop] = (error as any)[prop];
+  });
+
+  if (mode === 'string' && superJson.allowedErrorProps.includes('stack')) {
+    baseError.stack = processStackString(error.stack ?? '', options!);
+  }
+  if (mode === 'frames' && superJson.allowedErrorProps.includes('stackFrames')) {
+    baseError.stackFrames = processStackFrames(error.stack ?? '', options!);
+  }
+
+  return superJson.errorClassRegistry.getProcessor(error.name)?.(baseError) ?? baseError;
