export type ErrorStackMode = 'off' | 'string' | 'frames';
export type StripInternalFrames =
  | 'none'
  | 'node'
  | 'superjson'
  | 'node_and_superjson';
export type RedactPaths = 'none' | 'basename' | 'strip_cwd';
export type IncludeCauses = 'none' | 'direct' | 'deep';

export interface ErrorStackOptions {
  mode?: ErrorStackMode;
  normalizeNewlines?: boolean;
  trimLeadingWhitespace?: boolean;
  maxStackLines?: number;
  stripInternalFrames?: StripInternalFrames;
  redactPaths?: RedactPaths;
  includeCauses?: IncludeCauses;
  maxCauseDepth?: number;
  sanitizeMessage?: boolean;
  classFilter?: string | string[];
}

export interface NormalizedErrorStackOptions {
  mode: ErrorStackMode;
  normalizeNewlines: boolean;
  trimLeadingWhitespace: boolean;
  maxStackLines?: number;
  stripInternalFrames: StripInternalFrames;
  redactPaths: RedactPaths;
  includeCauses: IncludeCauses;
  maxCauseDepth: number;
  sanitizeMessage: boolean;
  classFilter?: string[];
}

const modes: ErrorStackMode[] = ['off', 'string', 'frames'];
const stripModes: StripInternalFrames[] = [
  'none',
  'node',
  'superjson',
  'node_and_superjson',
];
const redactModes: RedactPaths[] = ['none', 'basename', 'strip_cwd'];
const causeModes: IncludeCauses[] = ['none', 'direct', 'deep'];

export function normalizeErrorStackOptions(
  value: unknown
): NormalizedErrorStackOptions | undefined {
  if (typeof value !== 'object' || value === null || Array.isArray(value)) {
    return undefined;
  }

  const input = value as ErrorStackOptions;
  const mode = modes.includes(input.mode as ErrorStackMode)
    ? input.mode!
    : 'off';
  const maxStackLines = input.maxStackLines;
  const invalidMaxStackLines =
    maxStackLines !== undefined &&
    (!Number.isInteger(maxStackLines) || maxStackLines <= 0);
  const includeCauses = causeModes.includes(
    input.includeCauses as IncludeCauses
  )
    ? input.includeCauses!
    : 'none';
  const invalidCauseDepth =
    input.maxCauseDepth !== undefined && !Number.isInteger(input.maxCauseDepth);
  const classFilter = Array.isArray(input.classFilter)
    ? input.classFilter.filter(
        (name): name is string => typeof name === 'string'
      )
    : typeof input.classFilter === 'string'
    ? [input.classFilter]
    : undefined;

  return {
    mode: invalidMaxStackLines ? 'off' : mode,
    normalizeNewlines: input.normalizeNewlines === true,
    trimLeadingWhitespace: input.trimLeadingWhitespace !== false,
    maxStackLines,
    stripInternalFrames: stripModes.includes(
      input.stripInternalFrames as StripInternalFrames
    )
      ? input.stripInternalFrames!
      : 'none',
    redactPaths: redactModes.includes(input.redactPaths as RedactPaths)
      ? input.redactPaths!
      : 'none',
    includeCauses: invalidCauseDepth ? 'none' : includeCauses,
    maxCauseDepth: input.maxCauseDepth === undefined ? 16 : input.maxCauseDepth,
    sanitizeMessage: input.sanitizeMessage === true,
    classFilter: classFilter?.length ? classFilter : undefined,
  };
}
import { NormalizedErrorStackOptions } from './error-options.js';

export interface StackFrame {
  raw: string;
}

export function normalizeStackNewlines(stack: string): string {
  return stack.replace(/\r\n?|\n/g, '\n');
}

function shouldStrip(
  line: string,
  options: NormalizedErrorStackOptions
): boolean {
  const node = line.includes('node:internal');
  const superjson = /src\/(transformer|plainer|index)\.ts/.test(line);
  return (
    (options.stripInternalFrames === 'node' && node) ||
    (options.stripInternalFrames === 'superjson' && superjson) ||
    (options.stripInternalFrames === 'node_and_superjson' &&
      (node || superjson))
  );
}

function redact(line: string, options: NormalizedErrorStackOptions): string {
  if (options.redactPaths === 'strip_cwd') {
    const cwd = process.cwd().replace(/\\/g, '/');
    return line.replace(new RegExp(escapeRegExp(cwd), 'g'), '');
  }
  if (options.redactPaths === 'basename') {
    return line.replace(
      /((?:file:\/\/)?(?:[A-Za-z]:)?[^()\s]*[\\/])([^\\/()\s]+(?::\d+(?::\d+)?)?)/g,
      '$2'
    );
  }
  return line;
}

function escapeRegExp(value: string): string {
  return value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function initialLines(
  stack: string,
  options: NormalizedErrorStackOptions
): string[] {
  const value = options.normalizeNewlines
    ? normalizeStackNewlines(stack)
    : stack;
  return value
    .split('\n')
    .map((line, index) =>
      index > 0 && options.trimLeadingWhitespace
        ? line.replace(/^\s+/, '')
        : line
    );
}

export function processStackString(
  stack: string,
  options: NormalizedErrorStackOptions
): string {
  let lines = initialLines(stack, options).map(line => redact(line, options));
  if (options.maxStackLines !== undefined)
    lines = lines.slice(0, options.maxStackLines);
  lines = [
    lines[0],
    ...lines.slice(1).filter(line => !shouldStrip(line, options)),
  ];
  return lines.join('\n');
}

export function processStackFrames(
  stack: string,
  options: NormalizedErrorStackOptions
): StackFrame[] {
  let lines = initialLines(stack, options);
  lines = [
    lines[0],
    ...lines.slice(1).filter(line => !shouldStrip(line, options)),
  ];
  lines = lines.map(line => redact(line, options));
  if (options.maxStackLines !== undefined)
    lines = lines.slice(0, options.maxStackLines);
  return lines.map(raw => ({ raw }));
